const PAGES = ['home','docs','api','learn','stats','about']

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false)
  return (
    <button
      onClick={() => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1500) }}
      style={{ position:'absolute', top:8, right:8, background:'#252525', border:'1px solid #333',
        borderRadius:4, color: copied ? '#34c759' : '#666', padding:'3px 8px', fontSize:11,
        cursor:'pointer', fontFamily:'monospace' }}>
      {copied ? '✓' : 'copy'}
    </button>
  )
}

function CodeBlock({ code }) {
  return (
    <div style={{ position:'relative', background:'#111', border:'1px solid #252525',
      borderRadius:6, padding:'12px 52px 12px 14px', margin:'8px 0' }}>
      <pre style={{ margin:0, fontSize:13, color:'#c8192e', fontFamily:'monospace',
        overflowX:'auto', whiteSpace:'pre-wrap', wordBreak:'break-all' }}>
        <span style={{ color:'#444' }}>$ </span>{code}
      </pre>
      <CopyButton text={code} />
    </div>
  )
}

function Nav({ page, setPage, scrolled }) {
  const [menuOpen, setMenuOpen] = useState(false)
  return (
    <nav style={{
      position:'fixed', top:0, left:0, right:0, zIndex:100,
      background: scrolled ? 'rgba(13,13,13,0.96)' : 'transparent',
      backdropFilter: scrolled ? 'blur(12px)' : 'none',
      borderBottom: scrolled ? '1px solid #1f1f1f' : 'none',
      transition:'all 0.2s',
    }}>
      <div style={{ maxWidth:1100, margin:'0 auto', padding:'0 20px',
        display:'flex', alignItems:'center', justifyContent:'space-between', height:56 }}>
        <div onClick={() => setPage('home')}
          style={{ display:'flex', alignItems:'center', gap:10, cursor:'pointer' }}>
          <img src={LOGO_SRC} alt="HyperNix" style={{ height:30, width:'auto' }} />
          <span style={{ color:'#f0f0f0', fontWeight:700, fontSize:16, letterSpacing:'-0.4px' }}>hypernix</span>
        </div>
        <div className="desk-nav" style={{ display:'flex', gap:24, alignItems:'center' }}>
          {PAGES.map(p => (
            <button key={p} onClick={() => setPage(p)} style={{
              background:'none', border:'none', cursor:'pointer', fontSize:13,
              color: page === p ? '#c8192e' : '#666',
              fontWeight: page === p ? 700 : 400, textTransform:'capitalize',
            }}>{p}</button>
          ))}
          <a href="https://github.com/minerofthesoal/hypernix-pip" target="_blank" rel="noreferrer"
            style={{ color:'#444', fontSize:13, textDecoration:'none' }}>GitHub ↗</a>
        </div>
        <button className="mob-btn" onClick={() => setMenuOpen(!menuOpen)}
          style={{ display:'none', background:'none', border:'none', color:'#888', fontSize:22, cursor:'pointer' }}>☰</button>
      </div>
      {menuOpen && (
        <div style={{ background:'#111', borderBottom:'1px solid #1f1f1f', padding:'12px 20px' }}>
          {PAGES.map(p => (
            <button key={p} onClick={() => { setPage(p); setMenuOpen(false) }} style={{
              display:'block', background:'none', border:'none',
              color: page === p ? '#c8192e' : '#888',
              fontSize:15, padding:'8px 0', cursor:'pointer',
              textTransform:'capitalize', width:'100%', textAlign:'left',
            }}>{p}</button>
          ))}
        </div>
      )}
    </nav>
  )
}

